#include <vector>
#include <string>
#include <algorithm>

using namespace std;

vector<long long> solve(vector<string> words) {
    int n = words.size();
    vector<long long> answer(n, 0);

    for (int i = 0; i < n; i++) {
        long long maxPrefix = 0;
        string prev = words[0];
        for (int j = 1; j < n; j++) {
            if (j == i) continue;
            string current = words[j];
            int len = 0;
            while (len < min(prev.length(), current.length()) && prev[len] == current[len]) {
                len++;
            }
            maxPrefix = max(maxPrefix, len);
            prev = current;
        }
        answer[i] = maxPrefix;
    }

    return answer;
}
